/**
 * Dashboard Page
 *
 * Protected page that displays user information and provides logout functionality.
 * This page is server-side protected by NextAuth middleware at /dashboard/* routes.
 *
 * @see apps/web/src/middleware.ts
 */

import { auth } from '@/lib/auth'
import { signOut } from '@/lib/auth'
import { DashboardLayout } from '@/components/dashboard-layout'

export default async function DashboardPage() {
  const session = await auth()

  if (!session?.user) {
    return null // Middleware should redirect, but handle gracefully
  }

  return (
    <DashboardLayout>
      <div className="max-w-4xl space-y-6">
        {/* Welcome Card */}
        <div className="bg-card rounded-lg shadow p-6 border">
          <h2 className="text-lg font-medium mb-4">
            Welcome to your dashboard
          </h2>
          <div className="space-y-2 text-sm text-muted-foreground">
            <p>
              <span className="font-medium">User ID:</span> {session.user.id}
            </p>
            <p>
              <span className="font-medium">Email:</span> {session.user.email}
            </p>
            {session.user.name && (
              <p>
                <span className="font-medium">Name:</span> {session.user.name}
              </p>
            )}
          </div>
        </div>

        {/* Info Card */}
        <div className="bg-muted/50 border border-muted rounded-lg p-4">
          <p className="text-sm text-muted-foreground">
            This page is protected by NextAuth middleware. If you are not authenticated,
            you will be redirected to the login page.
          </p>
        </div>

        {/* Logout Form */}
        <form
          action={async () => {
            'use server'
            await signOut({ redirectTo: '/login' })
          }}
        >
          <button
            type="submit"
            className="px-4 py-2 text-sm font-medium bg-primary text-primary-foreground rounded-md hover:bg-primary/90 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-primary"
          >
            Logout
          </button>
        </form>
      </div>
    </DashboardLayout>
  )
}
